package service

import (
	"errors"
	"fmt"
	"time"

	"refactor/types"
	"refactor/validation"
)

// CreateOrder creates a new order after validating the user and items.
func (s *UserOrderService) CreateOrder(userID string, items []types.OrderItem) (*types.Order, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	// Ensure user exists.
	if _, ok := s.users[userID]; !ok {
		return nil, fmt.Errorf("user %s not found", userID)
	}
	// Validate items.
	if err := validation.ValidateOrder(items, s.maxItems); err != nil {
		return nil, err
	}
	// Compute total.
	var total float64
	for _, it := range items {
		total += it.Price * float64(it.Quantity)
	}
	s.orderCounter++
	order := &types.Order{
		ID:        fmt.Sprintf("order-%d", s.orderCounter),
		UserID:    userID,
		Items:     items,
		Status:    "active",
		Total:     total,
		CreatedAt: time.Now().Format(time.RFC3339),
	}
	s.orders[order.ID] = order

	// Confirmation notification.
	itemLines := ""
	for _, it := range items {
		itemLines += fmt.Sprintf("  - %s (x%d): $%.2f\n", it.Name, it.Quantity, it.Price*float64(it.Quantity))
	}
	subject := fmt.Sprintf("Order %s confirmed", order.ID)
	body := fmt.Sprintf("Hi %s,\n\nYour order %s has been confirmed.\n\nItems:\n%s\nTotal: $%.2f\n\nThank you for your purchase!", s.users[userID].Name, order.ID, itemLines, total)
	s.notifications = append(s.notifications, types.Notification{
		To:      s.users[userID].Email,
		Subject: subject,
		Body:    body,
	})
	return order, nil
}

// GetOrder retrieves an order by ID.
func (s *UserOrderService) GetOrder(id string) (*types.Order, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	order, ok := s.orders[id]
	if !ok {
		return nil, fmt.Errorf("order %s not found", id)
	}
	return order, nil
}

// ListOrdersByUser returns all orders belonging to a specific user.
func (s *UserOrderService) ListOrdersByUser(userID string) ([]*types.Order, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	if _, ok := s.users[userID]; !ok {
		return nil, fmt.Errorf("user %s not found", userID)
	}
	var result []*types.Order
	for _, o := range s.orders {
		if o.UserID == userID {
			result = append(result, o)
		}
	}
	return result, nil
}

// CancelOrder cancels an order if the caller is the owner or an admin.
func (s *UserOrderService) CancelOrder(orderID, cancelledByUserID string) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	order, ok := s.orders[orderID]
	if !ok {
		return fmt.Errorf("order %s not found", orderID)
	}
	if order.Status == "cancelled" {
		return errors.New("order is already cancelled")
	}
	canceller, ok := s.users[cancelledByUserID]
	if !ok {
		return fmt.Errorf("user %s not found", cancelledByUserID)
	}
	// Permission check.
	isAdmin := false
	for _, r := range s.adminRoles {
		if canceller.Role == r {
			isAdmin = true
			break
		}
	}
	if !isAdmin && order.UserID != cancelledByUserID {
		return errors.New("permission denied: only order owner or admin can cancel")
	}
	order.Status = "cancelled"

	// Cancellation notification.
	if owner, exists := s.users[order.UserID]; exists {
		subject := fmt.Sprintf("Order %s cancelled", orderID)
		body := fmt.Sprintf("Hi %s,\n\nYour order %s has been cancelled.\n\nIf you did not request this, please contact support.\n\nBest regards,\nThe Team", owner.Name, orderID)
		s.notifications = append(s.notifications, types.Notification{
			To:      owner.Email,
			Subject: subject,
			Body:    body,
		})
	}
	return nil
}

// CalculateTotal computes the total price for a slice of order items.
func (s *UserOrderService) CalculateTotal(items []types.OrderItem) float64 {
	var total float64
	for _, it := range items {
		total += it.Price * float64(it.Quantity)
	}
	return total
}
