	"refactor/validation"
)

// ValidateEmail delegates to the validation package, preserving the original method.
func (s *UserOrderService) ValidateEmail(email string) error {
	return validation.ValidateEmail(email, s.emailDomain)
}

// ValidateOrder delegates to the validation package, preserving the original method.
func (s *UserOrderService) ValidateOrder(items []types.OrderItem) error {
	return validation.ValidateOrder(items, s.maxItems)
}

// CheckUserPermission remains unchanged but stays in this file to keep size small.
func (s *UserOrderService) CheckUserPermission(userID, targetUserID, permission string) (bool, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	user, ok := s.users[userID]
	if !ok {
		return false, fmt.Errorf("user %s not found", userID)
	}
	switch permission {
	case "admin":
		for _, r := range s.adminRoles {
			if user.Role == r {
				return true, nil
			}
		}
		return false, nil
	case "owner":
		return userID == targetUserID, nil
	case "admin_or_owner":
		if userID == targetUserID {
			return true, nil
		}
		for _, r := range s.adminRoles {
			if user.Role == r {
				return true, nil
			}
		}
		return false, nil
	default:
		return false, fmt.Errorf("unknown permission type: %s", permission)
	}
}
